import React, { useEffect, useState } from "react";
import api from "../api";
import { useNavigate } from "react-router-dom";

export default function FoodMenu() {
  const [foods, setFoods] = useState([]); // Array to store food items
  const [searchQuery, setSearchQuery] = useState(""); // State for search query
  const [loading, setLoading] = useState(true); // State for loading spinner
  const [debouncedSearchQuery, setDebouncedSearchQuery] = useState(""); // State for debounced search query
  const navigate = useNavigate();

  // Fetch food items from API
  useEffect(() => {
    const fetchFoods = async () => {
      try {
        const res = await api.get("/foods");
        setFoods(res.data); // Set the fetched food items in state
      } catch (error) {
        console.error("Error fetching foods:", error);
        alert("Something went wrong while fetching the food list.");
      } finally {
        setLoading(false); // Stop the loading spinner once data is fetched
      }
    };
    fetchFoods();
  }, []);

  // Debounced search to avoid multiple API calls on typing
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearchQuery(searchQuery);
    }, 500); // Set debouncing delay to 500ms
    return () => clearTimeout(timer); // Cleanup timeout on every change
  }, [searchQuery]);

  // Filter the foods based on the debounced search query
  const filteredFoods = foods.filter((food) =>
    food.name.toLowerCase().includes(debouncedSearchQuery.toLowerCase())
  );

  // Navigate to Add Food page
  const addFood = () => {
    navigate("/add-item");
  };

  // Mark food item as today's special
  const setTodayItem = async (foodId) => {
    try {
      await api.post("/foods/set-today-menu", { foodId });
      alert("Food marked for today!");
    } catch (error) {
      console.error("Error marking food for today:", error);
      alert("Failed to update today's menu.");
    }
  };

  // Navigate to Manage Food page (edit food details)
  const deleteevent = (foodId) => {
    navigate(`/manage/${foodId}`);
  };

  // Placeholder for user role (replace with your actual user role logic)
  const userRole = 'admin';

  return (
    <div className="container mt-5">
      <h2>Food Menu (Admin)</h2>

      {/* Search Bar */}
      <div className="d-flex justify-content-between mb-4">
        <input
          type="text"
          className="form-control w-50"
          placeholder="Search food..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)} // Update search query
        />
        {userRole === "admin" && (
          <button className="btn btn-primary" onClick={addFood}>
            Add Food
          </button>
        )}
      </div>

      {/* Loading Indicator */}
      {loading ? (
        <div className="d-flex justify-content-center">
          <div className="spinner-border text-primary" role="status">
            <span className="sr-only">Loading...</span>
          </div>
        </div>
      ) : (
        <div className="row">
          {filteredFoods.map((food) => (
            <div key={food._id} className="col-md-4 mb-4">
              <div className="card">
                {/* <img
                  src={food.image ? `http://localhost:5000/uploads/${food.image}` : "/fallback_image_url.png"}
                  alt={food.name}
                  className="card-img-top"
                  onError={(e) => e.target.src = '/fallback_image_url.png'} // Use fallback if image not found
                /> */}
                <div className="card-body">
                  <h5 className="card-title">{food.name}</h5>
                  <p className="card-text">{food.description}</p>

                  <div className="d-flex justify-content-between">
                    {userRole === "admin" && (
                      <>
                        <button
                          className="btn btn-success"
                          onClick={() => setTodayItem(food._id)}
                        >
                          Mark as Today’s Item
                        </button>
                        <button
                          className="btn btn-warning"
                          onClick={() => deleteevent(food._id)}
                        >
                          Manage
                        </button>
                      </>
                    )}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
